import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';

interface StaffMember {
  id: string;
  firstName: string;
  lastName: string;
  role: string;
  gender: string;
  email: string;
  mobile: string;
  address: string;
  nic: string;
  dob: string;
  status: 'Online' | 'Offline';
}

@Component({
  selector: 'app-staff',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './staff.component.html',
  styleUrls: ['./staff.component.scss']
})
export class StaffComponent implements OnInit {
  staffForm!: FormGroup;
  searchId: string = '';

  // بيانات تجريبية مطابقة للجدول بالصورة
  staffList: StaffMember[] = [
    { id: '1', firstName: 'Madhasha', lastName: 'Perera', role: 'Doctor', gender: 'Male', email: 'madhasha@gmail.com', mobile: '0714942914', nic: '992361131V', dob: '1999-08-23', status: 'Online' },
    { id: '2', firstName: 'Madhasha', lastName: 'Perera', role: 'Doctor', gender: 'Male', email: 'madhasha@gmail.com', mobile: '0714942914', nic: '992361131V', dob: '1999-08-23', status: 'Online' }

  ];

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.initForm();
  }

  initForm(): void {
    this.staffForm = this.fb.group({
      firstName: ['', Validators.required],
      lastName: ['', Validators.required],
      role: ['Doctor', Validators.required],
      gender: ['Male', Validators.required],
      email: ['', [Validators.required, Validators.email]],
      mobile: ['', Validators.required],
      address: ['', Validators.required],
      nic: ['', Validators.required],
      dob: ['', Validators.required],
      password: ['', [Validators.required, Validators.minLength(6)]],
      confirmPassword: ['', Validators.required]
    });
  }

  onRegister(): void {
    if (this.staffForm.valid) {
      const newStaff: StaffMember = {
        id: (this.staffList.length + 1).toString(),
        ...this.staffForm.value,
        status: 'Online'
      };
      this.staffList.push(newStaff);
      this.staffForm.reset({ role: 'Doctor', gender: 'Male' });
    } else {
      this.staffForm.markAllAsTouched();
    }
  }

  onUpdate(): void {
    console.log('Update triggering...', this.staffForm.value);
  }

  onDelete(): void {
    this.staffForm.reset({ role: 'Doctor', gender: 'Male' });
  }

  onSearch(id: string): void {
    const member = this.staffList.find(s => s.id === id);
    if (member) {
      this.staffForm.patchValue(member);
    } else {
      alert('Staff ID not found');
    }
  }
}
